package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileReader;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserParseFileTest {

    File mockFile;
    CSVFormat mockFormat;

    @BeforeEach
    void setup() {
        mockFile = mock(File.class);
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void parse_nullFile_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((File) null, mockFormat));
        assertEquals("file", ex.getMessage());
    }

    @Test
    void parse_nullFormat_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockFile, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_validFileAndFormat_returnsCSVParser() throws IOException {
        FileReader mockFileReader = mock(FileReader.class);
        try {
            // Use reflection to mock FileReader constructor call inside CSVParser.parse
            // Since Mockito.mockConstruction is unavailable, we rely on partial mocking or no mocking here.
            // Just call the method normally as mocking FileReader construction is not possible with Mockito 3.
            CSVParser parser = CSVParser.parse(mockFile, mockFormat);
            assertNotNull(parser);
            assertTrue(parser instanceof CSVParser);
        } finally {
            if (mockFileReader != null) {
                mockFileReader.close();
            }
        }
    }
}
